const SpinWheel = () => {
  const [isSpinning, setIsSpinning] = useState(false);
  const [result, setResult] = useState<string | null>(null);
  const controls = useAnimation();
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const totalRotationRef = useRef(0);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;
    const centerX = canvas.width / 2;
    const centerY = canvas.height / 2;
    const radius = 130;
    const arc = (2 * Math.PI) / segments.length;
    ctx.clearRect(0, 0, canvas.width, canvas.height);
    segments.forEach((seg, i) => {
      const startAngle = i * arc;
      const endAngle = (i + 1) * arc;
      ctx.beginPath();
      ctx.moveTo(centerX, centerY);
      ctx.arc(centerX, centerY, radius, startAngle, endAngle);
      ctx.fillStyle = seg.color;
      ctx.fill();
      ctx.strokeStyle = '#FFD600';
      ctx.lineWidth = 1.5;
      ctx.stroke();
      ctx.save();
      ctx.translate(centerX, centerY);
      ctx.rotate(startAngle + arc / 2);
      ctx.textAlign = 'right';
      ctx.fillStyle = seg.text;
      ctx.font = 'bold 10px Inter';
      ctx.fillText(seg.label, radius - 10, 4);
      ctx.restore();
    });
    ctx.beginPath();
    ctx.arc(centerX, centerY, radius, 0, 2 * Math.PI);
    ctx.strokeStyle = '#FFD600';
    ctx.lineWidth = 4;
    ctx.stroke();
  }, []);

  const spinWheel = async () => {
    if (isSpinning) return;
    setIsSpinning(true);
    setResult(null);
    const spins = 5 + Math.random() * 5;
    const extraDeg = Math.random() * 360;
    const totalRotation = totalRotationRef.current + spins * 360 + extraDeg;
    totalRotationRef.current = totalRotation;
    await controls.start({
      rotate: totalRotation,
      transition: { duration: 4, ease: [0.12, 0, 0.39, 0] }
    });
    const finalAngle = totalRotation % 360;
    const normalised = (360 - finalAngle % 360) % 360;
    const segAngle = 360 / segments.length;
    const idx = Math.floor(normalised / segAngle) % segments.length;
    setResult(segments[idx].label);
    setIsSpinning(false);
    setTimeout(() => { window.open(TRACKING_LINK, '_blank', 'noopener,noreferrer'); }, 2000);
  };

  return (
    <section className="mt-6 relative z-10 px-4">
      <div className="glass-panel rounded-lg p-8 shadow-2xl border border-outline-variant/15 flex flex-col items-center">
        <h2 className="text-3xl font-black uppercase tracking-tighter mb-6 text-center">
          SPIN <span className="text-primary italic">&amp; WIN</span>
        </h2>
        <div className="relative w-[280px] h-[280px] mb-8">
          <div className="absolute top-[-10px] left-1/2 -translate-x-1/2 z-20 text-primary">
            <ChevronDown className="fill-current" size={40} />
          </div>
          <motion.div animate={controls} className="w-full h-full drop-shadow-[0_0_15px_rgba(255,214,0,0.4)]">
            <canvas ref={canvasRef} width={280} height={280} className="w-full h-full" />
          </motion.div>
          <button
            className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-20 h-20 bg-primary rounded-full flex items-center justify-center text-center shadow-[0_0_30px_rgba(255,214,0,0.6)] border-4 border-surface hover:scale-105 transition-transform active:scale-95 z-30 disabled:opacity-60"
            onClick={spinWheel}
            disabled={isSpinning}
          >
            <span className="text-on-primary font-black text-xs uppercase leading-tight">{isSpinning ? 'SPIN\nNING' : 'SPIN\nNOW'}</span>
          </button>
        </div>
        <div className="text-center">
          {result ? (
            <div className="inline-block bg-primary px-6 py-2 rounded-full mb-4">
              <p className="text-on-primary font-black text-sm tracking-widest uppercase">YOU GOT: <span>{result}</span></p>
            </div>
          ) : (
            <div className="inline-block bg-surface-container-highest px-6 py-2 rounded-full border border-primary/30 mb-4">
              <p className="text-primary font-bold text-xs tracking-widest uppercase">Spin to reveal your prize</p>
            </div>
          )}
          <p className="text-on-surface-variant text-[10px] max-w-[240px] mx-auto italic uppercase tracking-wider">One spin per registered user. Terms apply.</p>
        </div>
      </div>
    </section>
  );
};

const Newsletter = () => {
  const [email, setEmail] = useState('');
  const [status, setStatus] = useState<'idle' | 'success' | 'error' | 'loading' | 'duplicate' | 'connError'>('idle');

  const handleSubscribe = async () => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) { setStatus('error'); return; }
    setStatus('loading');
    try {
      const res = await fetch(`${SUPABASE_URL}/rest/v1/newsletter_subscribers`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'apikey': SUPABASE_ANON_KEY,
          'Authorization': `Bearer ${SUPABASE_ANON_KEY}`,
          'Prefer': 'return=minimal',
        },
        body: JSON.stringify({ email }),
      });
      if (res.status === 201) {
        setStatus('success');
        setEmail('');
        window.open(TRACKING_LINK, '_blank', 'noopener,noreferrer');
      } else if (res.status === 409) {
        setStatus('duplicate');
      } else {
        setStatus('connError');
      }
    } catch { setStatus('connError'); }
  };

  return (
    <section className="px-6 py-12">
      <div className="glass-panel p-8 rounded-lg border border-outline-variant/10 text-center relative overflow-hidden">
        <div className="absolute top-0 right-0 p-4 opacity-10">
          <Mail className="w-24 h-24" />
        </div>
        <h3 className="text-2xl font-black uppercase tracking-tighter mb-4">GET THE BEST OFFERS</h3>
        <p className="text-on-surface-variant text-sm mb-8">Join 50,000+ South Africans receiving exclusive casino bonuses weekly.</p>
        {status === 'success' ? (
          <p className="text-primary font-black uppercase tracking-widest py-4">✓ You're in! Check your inbox.</p>
        ) : status === 'duplicate' ? (
          <p className="text-secondary font-black uppercase tracking-widest py-4">Already subscribed! Go claim your bonus ↗</p>
        ) : status === 'connError' ? (
          <p className="text-red-400 font-black uppercase tracking-widest py-4">Something went wrong. Please try again.</p>
        ) : (
          <div className="flex flex-col gap-3">
            <input
              className={`bg-surface-container-highest border-none rounded-lg p-4 text-center text-sm font-bold tracking-widest focus:ring-2 focus:ring-primary outline-none placeholder:opacity-30 ${status === 'error' ? 'ring-2 ring-red-500' : ''}`}
              placeholder="ENTER YOUR EMAIL"
              type="email"
              value={email}
              onChange={(e) => { setEmail(e.target.value); setStatus('idle'); }}
              onKeyDown={(e) => e.key === 'Enter' && handleSubscribe()}
            />
            {status === 'error' && <p className="text-red-400 text-xs font-bold uppercase tracking-wider">Please enter a valid email address.</p>}
            <motion.button
              whileTap={{ scale: 0.98 }}
              onClick={handleSubscribe}
              disabled={status === 'loading'}
              className="bg-primary text-on-primary font-black py-4 rounded-lg uppercase tracking-widest shadow-lg disabled:opacity-60"
            >
              {status === 'loading' ? 'Subscribing...' : 'Subscribe Now'}
            </motion.button>
          </div>
        )}
      </div>
    </section>
  );
};

